STLCExtended_progress.solution:
Theorem progress : forall t T,
  empty |-- t \in T ->
  value t \/ (exists t', t --> t').
Proof with eauto.
  intros t T Ht.
  remember empty as Gamma.
  induction Ht; subst; auto;
    try (right; destruct IHHt as [Hv | [t' Hs]]; auto;
         try (inversion Hv; subst; eauto; solve_by_invert));
    try (right; destruct IHHt1 as [Hv1 | [t1' Hs1]]; auto;
         try (destruct IHHt2 as [Hv2 | [t2' Hs2]]; auto;
              try (inversion Hv1; subst; eauto; solve_by_invert))).
  - (* var *) inversion H.
Qed.
